CREATE TABLE teams (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug citext NOT NULL UNIQUE, name text NOT NULL, slogan text NOT NULL DEFAULT '', description text NOT NULL DEFAULT '', flag_asset_key text NOT NULL DEFAULT '', banner_asset_key text NOT NULL DEFAULT '', recruiting boolean NOT NULL DEFAULT true, captain_id uuid NOT NULL REFERENCES users(id), member_limit int NOT NULL DEFAULT 30 CHECK(member_limit BETWEEN 2 AND 100), score bigint NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE team_members (team_id uuid REFERENCES teams(id) ON DELETE CASCADE, user_id uuid REFERENCES users(id) ON DELETE CASCADE, role text NOT NULL CHECK(role IN ('captain','manager','member')), joined_at timestamptz NOT NULL DEFAULT now(), PRIMARY KEY(team_id,user_id));
CREATE UNIQUE INDEX team_members_single_team_uq ON team_members(user_id);
CREATE TABLE team_join_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id) ON DELETE CASCADE, user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, message text NOT NULL DEFAULT '', status text NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','approved','rejected','cancelled')), reviewed_by uuid REFERENCES users(id), reviewed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX team_join_requests_pending_uq ON team_join_requests(team_id,user_id) WHERE status='pending';
CREATE TABLE team_invitations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id), user_id uuid NOT NULL REFERENCES users(id), invited_by uuid NOT NULL REFERENCES users(id), status text NOT NULL DEFAULT 'pending', expires_at timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE team_announcements (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id) ON DELETE CASCADE, author_id uuid NOT NULL REFERENCES users(id), title text NOT NULL, content text NOT NULL, pinned boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE team_activity_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id) ON DELETE CASCADE, type text NOT NULL, actor_id uuid REFERENCES users(id), payload jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE team_roster_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), team_id uuid NOT NULL REFERENCES teams(id), competition_id uuid, members jsonb NOT NULL, created_at timestamptz NOT NULL DEFAULT now());

CREATE TABLE challenge_categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text NOT NULL UNIQUE, name text NOT NULL, description text NOT NULL DEFAULT '', scene_asset_key text NOT NULL DEFAULT '', sort_order int NOT NULL DEFAULT 0, enabled boolean NOT NULL DEFAULT true);
CREATE TABLE challenges (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug citext NOT NULL UNIQUE, category_id uuid NOT NULL REFERENCES challenge_categories(id), title text NOT NULL, difficulty text NOT NULL, summary text NOT NULL DEFAULT '', description_markdown text NOT NULL DEFAULT '', author_name text NOT NULL DEFAULT '', status text NOT NULL DEFAULT 'draft' CHECK(status IN ('draft','review','published','archived')), visibility text NOT NULL DEFAULT 'public', score_mode text NOT NULL DEFAULT 'fixed', base_score int NOT NULL DEFAULT 100, minimum_score int NOT NULL DEFAULT 100, maximum_score int NOT NULL DEFAULT 100, dynamic_decay int NOT NULL DEFAULT 0, is_dynamic boolean NOT NULL DEFAULT false, has_attachment boolean NOT NULL DEFAULT false, has_writeup boolean NOT NULL DEFAULT false, solve_count bigint NOT NULL DEFAULT 0, attempt_count bigint NOT NULL DEFAULT 0, published_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX challenges_list_idx ON challenges(status,category_id,difficulty);
CREATE TABLE challenge_tags (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name citext NOT NULL UNIQUE);
CREATE TABLE challenge_tag_links (challenge_id uuid REFERENCES challenges(id) ON DELETE CASCADE, tag_id uuid REFERENCES challenge_tags(id) ON DELETE CASCADE, PRIMARY KEY(challenge_id,tag_id));
CREATE TABLE challenge_files (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id) ON DELETE CASCADE, name text NOT NULL, object_key text NOT NULL, mime_type text NOT NULL, sha256 text NOT NULL, size bigint NOT NULL, public boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE challenge_hints (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id) ON DELETE CASCADE, title text NOT NULL, content_markdown text NOT NULL, cost int NOT NULL DEFAULT 0, sort_order int NOT NULL DEFAULT 0, released_at timestamptz);
CREATE TABLE challenge_knowledge_points (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id) ON DELETE CASCADE, name text NOT NULL, sort_order int NOT NULL DEFAULT 0);
CREATE TABLE challenge_flags (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id) ON DELETE CASCADE, kind text NOT NULL CHECK(kind IN ('static','dynamic','regex','checker','multi_stage')), hmac bytea, regex_pattern text NOT NULL DEFAULT '', stage int NOT NULL DEFAULT 1, enabled boolean NOT NULL DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE challenge_runtime_configs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL UNIQUE REFERENCES challenges(id) ON DELETE CASCADE, image_ref text NOT NULL, image_digest text NOT NULL DEFAULT '', internal_port int NOT NULL, protocol text NOT NULL DEFAULT 'http', cpu_milli int NOT NULL DEFAULT 250, memory_mb int NOT NULL DEFAULT 256, pids_limit int NOT NULL DEFAULT 128, disk_mb int NOT NULL DEFAULT 256, ttl_seconds int NOT NULL DEFAULT 7200, max_ttl_seconds int NOT NULL DEFAULT 14400, read_only_root_fs boolean NOT NULL DEFAULT true, environment_template jsonb NOT NULL DEFAULT '{}', enabled boolean NOT NULL DEFAULT true, updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE challenge_runtime_ports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), runtime_config_id uuid NOT NULL REFERENCES challenge_runtime_configs(id) ON DELETE CASCADE, name text NOT NULL, internal_port int NOT NULL, protocol text NOT NULL DEFAULT 'tcp', primary_port boolean NOT NULL DEFAULT false);
CREATE TABLE challenge_checker_configs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL UNIQUE REFERENCES challenges(id) ON DELETE CASCADE, image_ref text NOT NULL, timeout_ms int NOT NULL DEFAULT 3000, cpu_milli int NOT NULL DEFAULT 100, memory_mb int NOT NULL DEFAULT 64, network_policy text NOT NULL DEFAULT 'none');
CREATE TABLE challenge_relations (challenge_id uuid REFERENCES challenges(id) ON DELETE CASCADE, related_challenge_id uuid REFERENCES challenges(id) ON DELETE CASCADE, relation text NOT NULL DEFAULT 'similar', sort_order int NOT NULL DEFAULT 0, PRIMARY KEY(challenge_id,related_challenge_id));
CREATE TABLE challenge_publication_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id uuid NOT NULL REFERENCES challenges(id), actor_id uuid NOT NULL REFERENCES users(id), action text NOT NULL, version int NOT NULL, created_at timestamptz NOT NULL DEFAULT now());

CREATE TABLE competitions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), slug citext NOT NULL UNIQUE, name text NOT NULL, summary text NOT NULL DEFAULT '', description_markdown text NOT NULL DEFAULT '', mode text NOT NULL CHECK(mode IN ('individual','team')), status text NOT NULL DEFAULT 'draft' CHECK(status IN ('draft','registration','running','frozen','finished','archived')), scoring_mode text NOT NULL DEFAULT 'dynamic', visibility text NOT NULL DEFAULT 'public', banner_asset_key text NOT NULL DEFAULT '', theme_key text NOT NULL DEFAULT '', registration_starts_at timestamptz NOT NULL, registration_ends_at timestamptz NOT NULL, starts_at timestamptz NOT NULL, ends_at timestamptz NOT NULL, freeze_at timestamptz, team_min int NOT NULL DEFAULT 1, team_max int NOT NULL DEFAULT 5, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE competition_challenges (competition_id uuid REFERENCES competitions(id) ON DELETE CASCADE, challenge_id uuid REFERENCES challenges(id) ON DELETE CASCADE, score int NOT NULL, sort_order int NOT NULL DEFAULT 0, opens_at timestamptz, PRIMARY KEY(competition_id,challenge_id));
CREATE TABLE competition_participants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL REFERENCES competitions(id) ON DELETE CASCADE, user_id uuid NOT NULL REFERENCES users(id), team_id uuid REFERENCES teams(id), status text NOT NULL DEFAULT 'registered', registered_at timestamptz NOT NULL DEFAULT now(), roster_snapshot jsonb NOT NULL DEFAULT '[]');
CREATE UNIQUE INDEX competition_participant_user_uq ON competition_participants(competition_id,user_id) WHERE team_id IS NULL;
CREATE UNIQUE INDEX competition_participant_team_uq ON competition_participants(competition_id,team_id) WHERE team_id IS NOT NULL;
CREATE TABLE competition_announcements (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL REFERENCES competitions(id) ON DELETE CASCADE, title text NOT NULL, content text NOT NULL, published_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE competition_scoring_rules (competition_id uuid PRIMARY KEY REFERENCES competitions(id) ON DELETE CASCADE, config jsonb NOT NULL DEFAULT '{}', updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE competition_freeze_rules (competition_id uuid PRIMARY KEY REFERENCES competitions(id) ON DELETE CASCADE, freeze_at timestamptz NOT NULL, public_mode text NOT NULL DEFAULT 'snapshot');
CREATE TABLE competition_settlements (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), competition_id uuid NOT NULL UNIQUE REFERENCES competitions(id), status text NOT NULL, snapshot_id uuid, settled_by uuid REFERENCES users(id), settled_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());

