DROP TABLE IF EXISTS competition_settlements,competition_freeze_rules,competition_scoring_rules,competition_announcements,competition_participants,competition_challenges,competitions,challenge_publication_logs,challenge_relations,challenge_checker_configs,challenge_runtime_ports,challenge_runtime_configs,challenge_flags,challenge_knowledge_points,challenge_hints,challenge_files,challenge_tag_links,challenge_tags,challenges,challenge_categories,team_roster_snapshots,team_activity_events,team_announcements,team_invitations,team_join_requests,team_members,teams CASCADE;
